{
  "name": "django-orm-intellisense",
  "displayName": "Django ORM Intellisense",
  "description": "Framework-aware autocomplete, hover, go-to-definition, and diagnostics for Django ORM lookup paths, relation strings, and queryset chains.",
  "version": "0.1.5",
  "publisher": "newdlops",
  "license": "MIT",
  "repository": {
    "type": "git",
    "url": "https://github.com/newdlops/django-orm-intellisense.git"
  },
  "homepage": "https://github.com/newdlops/django-orm-intellisense",
  "bugs": {
    "url": "https://github.com/newdlops/django-orm-intellisense/issues"
  },
  "engines": {
    "vscode": "^1.90.0"
  },
  "categories": [
    "Programming Languages",
    "Linters",
    "Other"
  ],
  "icon": "images/icon.png",
  "galleryBanner": {
    "color": "#0c4b33",
    "theme": "dark"
  },
  "activationEvents": [
    "onLanguage:python",
    "onCommand:djangoOrmIntellisense.showStatus",
    "onCommand:djangoOrmIntellisense.restartDaemon",
    "onCommand:djangoOrmIntellisense.configurePylanceDiagnostics",
    "onCommand:djangoOrmIntellisense.selectSettingsModule",
    "onCommand:djangoOrmIntellisense.selectPythonInterpreter"
  ],
  "main": "./out/extension.js",
  "contributes": {
    "commands": [
      {
        "command": "djangoOrmIntellisense.showStatus",
        "title": "Django ORM: Show Status (daemon health, workspace, model index)"
      },
      {
        "command": "djangoOrmIntellisense.restartDaemon",
        "title": "Django ORM: Restart Analysis Daemon"
      },
      {
        "command": "djangoOrmIntellisense.configurePylanceDiagnostics",
        "title": "Django ORM: Suppress Pylance False Positives (attribute-access, unknown-type)"
      },
      {
        "command": "djangoOrmIntellisense.selectSettingsModule",
        "title": "Django ORM: Select DJANGO_SETTINGS_MODULE"
      },
      {
        "command": "djangoOrmIntellisense.selectPythonInterpreter",
        "title": "Django ORM: Select Python Interpreter (.venv)"
      }
    ],
    "configuration": {
      "title": "Django ORM Intellisense",
      "properties": {
        "djangoOrmIntellisense.autoStart": {
          "type": "boolean",
          "default": true,
          "description": "Automatically start the analysis daemon when a Python file is opened. Set to false to require manual restart."
        },
        "djangoOrmIntellisense.pythonInterpreter": {
          "type": "string",
          "default": "",
          "scope": "resource",
          "description": "Path to the Python interpreter for the analysis daemon. Accepts a virtualenv directory (.venv) or a Python executable path. Falls back to python3 if empty. Use Cmd+Shift+P → 'Django ORM: Select Python Interpreter' to browse."
        },
        "djangoOrmIntellisense.settingsModule": {
          "type": "string",
          "default": "",
          "scope": "resource",
          "description": "DJANGO_SETTINGS_MODULE value. Auto-detected from manage.py if empty. Set explicitly for projects with multiple settings files."
        },
        "djangoOrmIntellisense.workspaceRoot": {
          "type": "string",
          "default": "",
          "scope": "resource",
          "description": "Django project root path. Use this when your VS Code workspace is a monorepo and the Django project lives in a subdirectory."
        },
        "djangoOrmIntellisense.logLevel": {
          "type": "string",
          "enum": [
            "off",
            "info",
            "debug"
          ],
          "default": "info",
          "scope": "window",
          "description": "Controls how much daemon lifecycle logging is written to the extension output channel."
        }
      }
    }
  },
  "keywords": [
    "django",
    "orm",
    "python",
    "intellisense",
    "autocomplete",
    "queryset",
    "filter",
    "lookup"
  ],
  "scripts": {
    "vscode:prepublish": "npm run build:native && npm run compile",
    "compile": "tsc -p ./",
    "watch": "tsc -watch -p ./",
    "build:native": "bash scripts/build-native.sh",
    "build:native:dev": "CARGO_PROFILE=dev bash scripts/build-native.sh",
    "pretest": "npm run compile",
    "test": "vscode-test",
    "benchmark": "node out/test/benchmark.js",
    "benchmark:full": "node out/test/benchmark.js --full",
    "benchmark:json": "node out/test/benchmark.js --full --json",
    "benchmark:python": "cd python && python -m benchmarks.bench_reindex",
    "stress": "node out/test/stress.js"
  },
  "devDependencies": {
    "@types/mocha": "^10.0.10",
    "@types/node": "^20.17.30",
    "@types/vscode": "^1.90.0",
    "@vscode/test-cli": "^0.0.10",
    "@vscode/test-electron": "^2.5.2",
    "typescript": "^5.8.3"
  },
  "dependencies": {
    "vscode-languageclient": "^9.0.1",
    "vscode-languageserver": "^9.0.1",
    "vscode-languageserver-textdocument": "^1.0.12"
  }
}
